import {Component} from '@angular/core';
import { InuSvgSwitzerland } from 'inugami-ng/components/inu-svg-switzerland';

interface CantonValue {
  name: string;
  level: number;
}

interface MyFormModel {
  cantons: CantonValue[];
}

@Component({
  templateUrl: './my-app.view.html',
  styleUrls: ['./my-app.view.scss'],
  imports: [
    InuSvgSwitzerland
  ]
})
export class MyAppView {
  colorLevel = signal<InuSvgSwitzerlandStyleGenerator>(SVG_SWITZERLAND_MAT_LAB);
  actionHandler!: InuSvgSwitzerlandAction;
  actionHandlerForm!: InuSvgSwitzerlandAction;

  formModel = signal<MyFormModel>({
    cantons: [
      {name: 'VD', level: 35},
      {name: 'GE', level: 25},
      {name: 'FR', level: 10},
      {name: 'VS', level: 5}
    ]
  });
  myForm: FieldTree<MyFormModel> = form(this.formModel, (path) => {
  });

  //=======================================================
  // INIT
  //=======================================================
  constructor() {
    this.actionHandlerForm = {
      onSelected: (value) => this.onCantonSelectedForm(value),
      onDeselected: (value) => this.onCantonDeselectedForm(value),
      toggleSelectState: () => false
    }
  }

  //=======================================================
  // MATCHER
  //=======================================================
  private cantonMatcher(selectItem: InuSelectItem<any>,
                        value: any): InuSelectItem<any> | undefined {
    if (selectItem.id != value.name) {
      return undefined;
    }
    selectItem.value = value;
    return selectItem;
  }
  //=======================================================
  // HANDLER
  //=======================================================
  private onCantonSelectedForm(value: InuSelectItem<any>): CantonValue {
    const currentValue = value?.value?.level == undefined ? 0 : (Number(value?.value?.level));
    const result = currentValue + 1;
    return {
      name: value.id,
      level: result > MAX_LEVEL ? MAX_LEVEL : result
    }
  }

  private onCantonDeselectedForm(value: InuSelectItem<any>): CantonValue {
    const currentValue = value?.value?.level == undefined ? 0 : (Number(value?.value?.level));
    const result = currentValue - 1;
    return {
      name: value.id,
      level: result <= 0 ? 0 : result
    }
  }
}


export const SVG_SWITZERLAND_COLORED: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return {
    styleclass: `colored-${selectItem.id} ${selectItem.selected ? 'selected' : ''}`
  }
}

export const SVG_SWITZERLAND_MONOCHROME: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return {
    styleclass: `monochrome ${selectItem.selected ? 'selected' : ''}`
  }
}

export const SVG_SWITZERLAND_LEVEL_MONOCHROME_BLUE: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return SVG_SWITZERLAND_LEVEL_MONOCHROME_GENERATOR(selectItem, 200, 0, 10);
}
export const SVG_SWITZERLAND_LEVEL_MONOCHROME_RED: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return SVG_SWITZERLAND_LEVEL_MONOCHROME_GENERATOR(selectItem, 0, 0, 10);
}
export const SVG_SWITZERLAND_LEVEL_MONOCHROME_GREEN: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return SVG_SWITZERLAND_LEVEL_MONOCHROME_GENERATOR(selectItem, 100, 0, 10);
}

export const SVG_SWITZERLAND_LEVEL_COLOR_100: InuSvgSwitzerlandStyleGenerator = (selectItem: InuSelectItem<any>): SvgStyle | undefined => {
  return SVG_SWITZERLAND_LEVEL_COLOR_GENERATOR(selectItem, 0, 100);
}

export const SVG_SWITZERLAND_LEVEL_COLOR_GENERATOR = (selectItem: InuSelectItem<any>,
                                                      min: number,
                                                      max: number,
                                                      colors?:string[]) => {
  const color = GET_COLOR(COMPUTE_PERCENT(Number(selectItem.value) || 0, min, max), colors?colors:COLORS_MATLAB);

  return {
    styleclass: `color-level`,
    style: `fill:${color};`
  };
}


export class MyAppView {
  actionHandler!: InuSvgSwitzerlandAction;
  //...

  //=======================================================
  // INIT
  //=======================================================
  constructor() {
    this.actionHandlerForm = {
      onSelected: (value) => this.onCantonSelectedForm(value),
      onDeselected: (value) => this.onCantonDeselectedForm(value),
      toggleSelectState: () => false
    }
  }

  //=======================================================
  // HANDLER
  //=======================================================
  private onCantonSelectedForm(value: InuSelectItem<any>): CantonValue {
    const currentValue = value?.value?.level == undefined ? 0 : (Number(value?.value?.level));
    const result = currentValue + 1;
    return {
      name: value.id,
      level: result > MAX_LEVEL ? MAX_LEVEL : result
    }
  }

  private onCantonDeselectedForm(value: InuSelectItem<any>): CantonValue {
    const currentValue = value?.value?.level == undefined ? 0 : (Number(value?.value?.level));
    const result = currentValue - 1;
    return {
      name: value.id,
      level: result <= 0 ? 0 : result
    }
  }
}


protected valueExtractor(selectItem: InuSelectItem<any>): number | undefined {
    return selectItem && selectItem.value ? selectItem.value.level : undefined;
}
